from typing import Dict, List, Optional, Tuple
from enum import Enum
from dataclasses import dataclass
from decimal import Decimal

class UserTier(Enum):
    GUEST = "guest"
    BASIC = "basic"
    PREMIUM = "premium"
    ADMIN = "admin"

class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"

@dataclass
class CartItem:
    product_id: str
    name: str
    price: Decimal
    quantity: int
    taxable: bool = True

@dataclass
class DiscountCode:
    code: str
    type: DiscountType
    value: Decimal
    min_purchase: Decimal = Decimal('0')
    allowed_tiers: List[UserTier] = None
    
    def __post_init__(self):
        if self.allowed_tiers is None:
            self.allowed_tiers = [UserTier.BASIC, UserTier.PREMIUM, UserTier.ADMIN]

@dataclass
class User:
    user_id: str
    tier: UserTier
    email: str

@dataclass
class Order:
    order_id: str
    user_id: str
    items: List[CartItem]
    subtotal: Decimal
    discount_amount: Decimal
    discount_code: Optional[str]
    tax_amount: Decimal
    total: Decimal
    payment_status: str

class CheckoutError(Exception):
    pass

class ValidationError(CheckoutError):
    pass

class DiscountError(CheckoutError):
    pass

class PaymentError(CheckoutError):
    pass

def validate_cart_items(cart_items: List[CartItem]) -> Tuple[bool, List[CartItem], Decimal]:
    """
    Step 1: Validate cart items
    Returns: (is_valid, validated_items, subtotal)
    """
    if not cart_items:
        raise ValidationError("Cart is empty")
    
    validated_items = []
    subtotal = Decimal('0')
    
    for item in cart_items:
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for item {item.name}")
        
        if item.price < 0:
            raise ValidationError(f"Invalid price for item {item.name}")
        
        item_total = item.price * item.quantity
        subtotal += item_total
        validated_items.append(item)
    
    return True, validated_items, subtotal

def apply_discount_code(
    user: User,
    discount_code: Optional[str],
    subtotal: Decimal,
    available_codes: Dict[str, DiscountCode]
) -> Tuple[Decimal, Optional[str]]:
    """
    Step 2: Apply discount codes with permission validation
    Returns: (discount_amount, applied_code)
    """
    if not discount_code:
        return Decimal('0'), None
    
    if discount_code not in available_codes:
        raise DiscountError(f"Invalid discount code: {discount_code}")
    
    discount = available_codes[discount_code]
    
    # Validate user tier permissions
    if user.tier not in discount.allowed_tiers:
        raise DiscountError(
            f"User tier {user.tier.value} is not authorized to use code {discount_code}. "
            f"Required tiers: {[t.value for t in discount.allowed_tiers]}"
        )
    
    # Check minimum purchase requirement
    if subtotal < discount.min_purchase:
        raise DiscountError(
            f"Minimum purchase of {discount.min_purchase} required for code {discount_code}. "
            f"Current subtotal: {subtotal}"
        )
    
    # Calculate discount amount
    if discount.type == DiscountType.PERCENTAGE:
        discount_amount = subtotal * (discount.value / Decimal('100'))
    else:  # FIXED
        discount_amount = discount.value
    
    # Ensure discount doesn't exceed subtotal
    discount_amount = min(discount_amount, subtotal)
    
    return discount_amount, discount_code

def calculate_tax(
    cart_items: List[CartItem],
    subtotal: Decimal,
    discount_amount: Decimal,
    tax_rate: Decimal = Decimal('0.08')
) -> Decimal:
    """
    Step 3: Calculate tax on taxable items after discount
    Returns: tax_amount
    """
    # Calculate taxable amount
    taxable_amount = Decimal('0')
    total_item_value = Decimal('0')
    
    for item in cart_items:
        item_value = item.price * item.quantity
        total_item_value += item_value
        if item.taxable:
            taxable_amount += item_value
    
    # Apply discount proportionally to taxable items
    if total_item_value > 0:
        discount_on_taxable = (taxable_amount / total_item_value) * discount_amount
        taxable_after_discount = taxable_amount - discount_on_taxable
    else:
        taxable_after_discount = Decimal('0')
    
    # Calculate tax
    tax_amount = taxable_after_discount * tax_rate
    
    return tax_amount.quantize(Decimal('0.01'))

def process_payment(
    user: User,
    total_amount: Decimal,
    payment_method: str = "credit_card"
) -> Tuple[bool, str]:
    """
    Step 4: Process payment
    Returns: (success, transaction_id)
    """
    if total_amount < 0:
        raise PaymentError("Invalid payment amount")
    
    if total_amount == 0:
        return True, "NO_CHARGE"
    
    # Simulate payment processing
    # In real implementation, this would integrate with payment gateway
    if payment_method not in ["credit_card", "paypal", "bank_transfer"]:
        raise PaymentError(f"Invalid payment method: {payment_method}")
    
    # Simulate successful payment
    transaction_id = f"TXN_{user.user_id}_{hash(str(total_amount))}"[:20]
    
    return True, transaction_id

def create_order_record(
    user: User,
    cart_items: List[CartItem],
    subtotal: Decimal,
    discount_amount: Decimal,
    discount_code: Optional[str],
    tax_amount: Decimal,
    total: Decimal,
    transaction_id: str
) -> Order:
    """
    Step 5: Create order record
    Returns: Order object
    """
    order_id = f"ORD_{user.user_id}_{hash(transaction_id)}"[:20]
    
    order = Order(
        order_id=order_id,
        user_id=user.user_id,
        items=cart_items,
        subtotal=subtotal,
        discount_amount=discount_amount,
        discount_code=discount_code,
        tax_amount=tax_amount,
        total=total,
        payment_status="completed" if transaction_id else "failed"
    )
    
    return order

def checkout(
    user: User,
    cart_items: List[CartItem],
    discount_code: Optional[str] = None,
    available_codes: Dict[str, DiscountCode] = None,
    tax_rate: Decimal = Decimal('0.08'),
    payment_method: str = "credit_card"
) -> Order:
    """
    Multi-step checkout process that validates and processes an order
    """
    if available_codes is None:
        available_codes = {}
    
    try:
        # Step 1: Validate cart items
        is_valid, validated_items, subtotal = validate_cart_items(cart_items)
        
        # Step 2: Apply discount code with permission validation
        discount_amount, applied_code = apply_discount_code(
            user, discount_code, subtotal, available_codes
        )
        
        # Step 3: Calculate tax
        tax_amount = calculate_tax(validated_items, subtotal, discount_amount, tax_rate)
        
        # Calculate total
        total = subtotal - discount_amount + tax_amount
        
        # Step 4: Process payment
        payment_success, transaction_id = process_payment(user, total, payment_method)
        
        if not payment_success:
            raise PaymentError("Payment processing failed")
        
        # Step 5: Create order record
        order = create_order_record(
            user, validated_items, subtotal, discount_amount,
            applied_code, tax_amount, total, transaction_id
        )
        
        return order
        
    except CheckoutError:
        raise
    except Exception as e:
        raise CheckoutError(f"Checkout failed: {str(e)}")


